import urllib.request, json, time

# AWS publishes IP ranges; you can curl regional HTTPS endpoints to measure latency
REGIONS = [
    "us-east-1", "us-west-2", "eu-west-1",
    "ap-southeast-1", "ap-northeast-1", "ap-south-1"
]

results = {}
for region in REGIONS:
    url = f"https://dynamodb.{region}.amazonaws.com"
    try:
        start = time.monotonic()
        req = urllib.request.Request(url, method="HEAD")
        urllib.request.urlopen(req, timeout=5)
        elapsed_ms = (time.monotonic() - start) * 1000
        results[region] = round(elapsed_ms, 1)
    except Exception as e:
        results[region] = f"error: {e}"

for region, ms in sorted(results.items(), key=lambda x: x[1] if isinstance(x[1], float) else 9999):
    print(f"{region:<25} {ms}ms")

import boto3, sys

REQUIRED_SERVICES = ["bedrock", "vpc-lattice", "securityhub"]
APPROVED_REGIONS = {"eu-west-1", "eu-central-1", "eu-north-1"}  # GDPR-compliant list

def validate_region(region: str) -> list[str]:
    """Return list of validation failures; empty list = region is valid."""
    failures = []

    if region not in APPROVED_REGIONS:
        failures.append(f"{region} not in compliance-approved region list")
        return failures  # stop early; rest is moot

    # Check required services via SSM parameter store
    ssm = boto3.client("ssm", region_name="us-east-1")
    for svc in REQUIRED_SERVICES:
        path = f"/aws/service/global-infrastructure/services/{svc}/regions"
        try:
            params = ssm.get_parameters_by_path(Path=path)["Parameters"]
            available = {p["Value"] for p in params}
            if region not in available:
                failures.append(f"Service '{svc}' not available in {region}")
        except Exception as e:
            failures.append(f"Could not check '{svc}': {e}")

    return failures

if __name__ == "__main__":
    target = sys.argv[1]
    issues = validate_region(target)
    if issues:
        print("Region validation FAILED:")
        for issue in issues:
            print(f"  - {issue}")
        sys.exit(1)
    else:
        print(f"{target}: all checks passed")
        sys.exit(0)
